      "prediction-api/ — FastAPI service with LightGBM in-process inference",
      "prediction-api/model_loader.py — Hot-swap model loading with atomic pointer swap",
      "prediction-api/feature_assembler.py — Combines request features with Feature Store lookups",
      "training-pipeline/ — Airflow DAG or simple Python script for weekly retraining",
      "training-pipeline/train.py — LightGBM training with hyperparameter config",
      "training-pipeline/evaluate.py — Holdout evaluation + comparison against active model",
      "model-registry/ — PostgreSQL schema + S3 artifact storage + promotion/rollback CLI",
      "feature-pipeline/ — Batch jobs for computing and refreshing features in Redis",
      "monitoring/ — Shadow scoring job + Grafana dashboard definitions",
      "shared/feature_definitions.py — Single source of truth for feature schemas (prevents training-serving skew)"
    ],
    "patterns_to_follow": "Use FastAPI for the Prediction API (async, fast, good for ML serving). Use LightGBM's native Python API for inference (not sklearn wrapper — faster). Feature Store reads should use connection pooling with a 10ms timeout. All model artifacts stored in S3 with immutable versioned keys. Training pipeline should be idempotent — safe to re-run. Use structured logging throughout for observability. Prediction responses must include model_version for traceability.",
    "pitfalls_to_avoid": [
      "Do NOT call external APIs (weather, traffic) synchronously during inference — precompute everything",
      "Do NOT use pickle for model serialization — use LightGBM native format for deterministic loading",
      "Do NOT skip the training-serving skew check — it is the #1 cause of ML system failures in production",
      "Do NOT build a custom model serving framework — use in-process LightGBM, it is fast enough",
      "Do NOT over-engineer the model registry — a PostgreSQL table with (version, s3_path, status, metrics_json, created_at) is sufficient to start",
      "Do NOT deploy new models without automated comparison against the current active model on a holdout set",
      "Do NOT log predictions synchronously — use async fire-and-forget to a message queue to avoid adding latency to the critical path"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "In-process LightGBM serving will meet 100ms P99 — LightGBM inference on 6 features is typically <1ms",
      "Model registry with promotion gates is the right pattern for weekly retraining with rollback",
      "Redis Feature Store will meet latency requirements for precomputed feature serving",
      "Architecture complexity is calibrated for a 4-person team"
    ],
    "low_confidence_areas": [
      "Exact feature engineering choices — depends on data exploration by ML engineers (e.g., whether zone should be one-hot encoded or embedding-based)",
      "Whether weekly retraining frequency is sufficient — depends on delivery pattern volatility which is unknown",
      "Monitoring thresholds for auto-rollback — must be tuned empirically after observing real prediction error distributions"
    ],
    "assumptions": [
      "Tabular features only (no images, text, or route geometry) — LightGBM is appropriate",
      "Prediction volume is moderate (< 10K RPS) — a few API instances with in-process models can handle this",
      "Team has Python proficiency and basic infrastructure skills (Redis, PostgreSQL, S3)",
      "Checkout service can tolerate a degraded prediction (wider confidence interval) if Feature Store is temporarily unavailable",
      "Delivery data volume is manageable for single-machine training (< 100M rows per weekly batch)"
    ]
  }
}
